import type { SVGProps } from "react";
import { cn } from "@/lib/utils";

export type SvgIconComponent = React.FC<SVGProps<SVGSVGElement>>;

const sizes = {
  xs: "h-3.5 w-3.5",
  sm: "h-4 w-4",
  md: "h-5 w-5",
  lg: "h-6 w-6",
  xl: "h-8 w-8",
} as const;

/** SVG ikonni standart o'lcham va stillar bilan chiqaradi. */
export function SvgIcon({
  icon: Icon,
  size = "md",
  className,
  ...props
}: {
  icon: SvgIconComponent;
  size?: keyof typeof sizes;
  className?: string;
} & SVGProps<SVGSVGElement>) {
  return (
    <Icon
      className={cn(sizes[size], "shrink-0", className)}
      fill="currentColor"
      aria-hidden
      {...props}
    />
  );
}

