/** Barcha maxsus SVG ikonlar markaziy ro'yxati */
export const SVG_ICONS = {
  sun: SVG_SUN,
  owl: SVG_OWL,
  chick: SVG_CHICK,
  turkey: SVG_TURKEY,
  penguin: SVG_PENGUIN,
  brain: SVG_BRAIN,
  skull: SVG_SKULL,
  world: SVG_WORLD,
  mole: SVG_MOLE,
  mouse: SVG_MOUSE,
  rabbit: SVG_RABBIT,
  scarecrow: SVG_SCARECROW,
  zombie: SVG_ZOMBIE,
  deer: SVG_DEER,
  cat: SVG_CAT,
  dog: SVG_DOG,
} as const satisfies Record<string, SvgIconComponent>;

export type SvgIconName = keyof typeof SVG_ICONS;

export function resolveSvgIcon(name: SvgIconName): SvgIconComponent {
  return SVG_ICONS[name];
}
